{"Question": "How do I create rule-based customer segments based on specific business criteria?", "Context": "I need to segment my customers using explicit business rules like spending thresholds and purchase frequency rather than algorithmic clustering.", "Code_Example": "from segmentationtools import SegmentationPipe, run_rule_based

# Create pipeline with customer data
pipeline = SegmentationPipe.from_dataframe(customer_df)

# Define segmentation rules using different conditions
rules = {
    'premium': {
        'annual_spend': ('>', 1000),
        'purchase_frequency': ('>=', 12)  # At least monthly
    },
    'regular': {
        'annual_spend': ('between', 500, 1000),
        'purchase_frequency': ('>=', 6)  # At least bi-monthly
    },
    'occasional': {
        'annual_spend': ('between', 100, 500),
        'days_since_last_purchase': ('<', 180)  # Active in last 6 months
    },
    'at_risk': {
        'days_since_last_purchase': ('between', 180, 365)  # Inactive 6-12 months
    },
    'inactive': {
        'days_since_last_purchase': ('>', 365)  # Inactive over 12 months
    }
}

# Apply rule-based segmentation
segmented_pipeline = pipeline | run_rule_based(
    rules=rules,
    segment_name='customer_lifecycle'
)

# Check the segments with both string labels and encoded numeric values
print(segmented_pipeline.data[['segment_customer_lifecycle', 'segment_customer_lifecycle_encoded']].head())", "Usage": "run_rule_based(rules={'high_value': {'spend': ('>', 1000)}, 'medium_value': {'spend': ('between', 500, 1000)}}, segment_name='value_segments')"}
